__kernel void Fan1(__global float *m_cuda, __global float *a_cuda, int Size, int t)
{
    int gx = (int)get_global_id(0);

    if (gx >= (Size - 1 - t)) return;

    m_cuda[Size * (gx + t + 1) + t] = a_cuda[Size * (gx + t + 1) + t] / a_cuda[Size * t + t];
}

__kernel void Fan2(__global float *m_cuda, __global float *a_cuda, __global float *b_cuda, int Size, int j1, int t)
{
    int xidx = (int)get_global_id(0);
    int yidx = (int)get_global_id(1);

    if (xidx >= (Size - 1 - t)) return;
    if (yidx >= (Size - t)) return;

    a_cuda[Size * (xidx + 1 + t) + (yidx + t)] -=
        m_cuda[Size * (xidx + 1 + t) + t] * a_cuda[Size * t + (yidx + t)];

    if (yidx == 0) {
        b_cuda[xidx + 1 + t] -= m_cuda[Size * (xidx + 1 + t) + (yidx + t)] * b_cuda[t];
    }
}
